import { IMessageDataWrapper, IMessageParser } from '@nitrots/nitro-renderer';

export class ATMOpenParser implements IMessageParser {
    private _username: string = '';
    private _cash: number = 0;
    private _bank: number = 0;

    public flush(): boolean {
        this._username = '';
        this._cash = 0;
        this._bank = 0;
        return true;
    }

    public parse(wrapper: IMessageDataWrapper): boolean {
        if (!wrapper) return false;

        // Must match the order from ATMOpenComposer.java
        this._username = wrapper.readString(); // 1️⃣ username
        this._cash = wrapper.readInt(); // 2️⃣ on-hand credits
        this._bank = wrapper.readInt(); // 3️⃣ bank credits

        return true;
    }

    public get username(): string {
        return this._username;
    }

    public get cash(): number {
        return this._cash;
    }

    public get bank(): number {
        return this._bank;
    }
}
